    'ara_pacis' => 
    array (
      'title' => 'L\'Ara Pacis e le sue raffigurazioni sulle monete',
      'lead' => 'L\'Ara Pacis nella numismatica romana.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'monete_romane_7g50r436.jpg',
            'alt' => 'moneta romana, monete romane',
            'link' => '__ROUTE:guide.rome_in_coins__',
          ),
          'body' => '<b><a href="__ROUTE:guide.rome_in_coins__">Stai cercando una moneta romana? In Italia il commercio ed il collezionismo di monete antiche di lecita provenienza è legale. Vieni a visitare il nostro Shop Online.</a></b><br>',
        ),
        1 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'neronearapacisb.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, ara pacis',
          ),
          'body' => '“Quando, sotto il consolato di Tiberio Nerone e Publio Quintilio, tornai a Roma dalla Spagna e dalla Gallia, dopo aver portato a termine con successo i programmi prestabiliti, il senato decretò che per il mio ritorno dovesse essere consacrato l’altare della Pace Augusta vicino al Campo Marzio, e ordinò che su di esso i magistrati, i sacerdoti e le vergini Vestali facessero ogni anno un sacrificio”. E’ con queste parole che Augusto nelle <i class="cf1">Res Gestae</i> (12), ci ha riferito la volontà del Senato di costruire un altare alla Pace, a seguito delle imprese da lui portate a termine a nord delle Alpi tra il 16 e il 13 a.C., tra cui il controllo definitivo dei valichi alpini, la visita alla Spagna finalmente pacificata, la fondazione di nuove colonie e l’imposizione dei nuovi tributi.  L’altare dedicato alla pace veniva così a trovarsi, non a caso, al centro del vasto pianoro sul quale tradizionalmente si svolgevano le manovre dell’esercito, della cavalleria e, in tempi più recenti, le esercitazioni ginniche della gioventù romana.  Questo monumento rappresenta una delle più significative testimonianze dell’arte augustea e simboleggia la pace e la prosperità raggiunte come risultato della <i class="cf1">Pax Romana</i>. La <i class="cf1">dedicatio </i>ebbe luogo il 30 gennaio del 9 a.C., data importante perché compleanno di Livia, moglie del <i class="cf1">princeps</i>.',
        ),
        2 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'arapacis.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, ara pacis',
          ),
          'body' => 'L’edificio era collocato nel Campo Marzio a pochi passi dalla via Flaminia e ai bordi della grande piazza dell’Horologium, l’enorme orologio solare tra le piazze del Parlamento e di S. Lorenzo in Lucina. Proprio l’obelisco egiziano, che era utilizzato come braccio indicatore (oggi in piazza Montecitorio), il 23 settembre di ogni anno avrebbe dovuto puntare la sua ombra verso l’ingresso dell’Ara Pacis a ricordare la data di nascita di Augusto. L’Ara, che è già rappresentata su monete di Tiberio dedicate al Divus Augustus Pater, ritorna anche su alcune emissioni neroniane: il conio è visibilmente di modesta fattura, non curato nei particolari come nelle serie tiberiane, ma la leggenda ARA PACIS non lascia dubbi sulla sua identificazione. Con questa emissione Nerone avrà voluto ricordare lo stesso Augusto ma anche la sua dinastia, la Claudia, che era presente e rappresentata attraverso i suoi più importanti membri sui fregi laterali del recinto esterno della stessa Ara. Nel fregio del lato sud, rimasto integro, sono riconoscibili Augusto e i maggiori rappresentanti di casa imperiale sistemati in fila, secondo un preciso ordine gerarchico di discendenza. All’epoca della dedica del monumento, nel 9 a.C., Nerone non era ancora nato, ma sono raffigurati i nonni paterni, Antonia Maggiore e L. Domizio Enobarbo e i figli, Domizia e soprattutto Cneo Domizio, il padre di Nerone, morto quando lui aveva circa 3 anni.<br>Francesca Barenghi',
        ),
      ),
    ),
    'temple_janus' => 
    array (
      'title' => 'Il culto del Dio Giano e la raffigurazione del santuario sulle monete romane',
      'lead' => 'Il tempio di Giano sulle monete romane.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'monete_romane_7g50r436.jpg',
            'alt' => 'moneta romana, monete romane',
            'link' => '__ROUTE:guide.rome_in_coins__',
          ),
          'body' => '<b><a href="__ROUTE:guide.rome_in_coins__">Stai cercando una moneta romana? In Italia il commercio ed il collezionismo di monete antiche di lecita provenienza è legale. Vieni a visitare il nostro Shop Online.</a></b><br>',
        ),
        1 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'nero.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, nerone',
          ),
          'body' => '<b class="fs14 cf1">Quando le porte del tempio di Giano erano chiuse …</b><br>Giano è il dio che guarda l’interno e l’esterno, che vede l’Oriente e l’Occidente, il passato e l’avvenire. Da questo la sua rappresentazione a due volti contrapposti, da cui i vari attributi di <i>biceps</i>, <i>biformis</i>, <i>ancipiti imagine</i>, <i>duplice imagine</i>, <i>gemina facies</i>. Giano fondò una città, da lui chiamata Gianicolo. Il suo regno fu felice e pieno di pace, e per questo in seguito venne onorato come dio della pace. Lo scrittore Macrobio, vissuto nel V secolo d.C., attribuisce le origini del culto di Giano alla guerra sabina, quando il nemico, entrato in città attraverso la <i>Porta Janualis</i>, fu sopraffatto da un torrente di acqua bollente, che improvvisamente fuoriuscì dal tempio di Giano. Per questo motivo fu decretato che durante le guerre le porte del tempio di Giano dovevano rimanere aperte affinché il dio potesse venire in aiuto in qualsiasi momento.',
        ),
        2 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'tempio_di_giano.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, aureo tempio di giano',
          ),
          'body' => 'Il culto di Giano venne associato a quello di Quirino; talvolta, detto culto venne indicato con il nome di Giano <i>Geminus</i>. Questo nome fu attribuito al santuario più antico del dio, che si trovava <i>ad infimum Argiletum</i>, a Roma e che conteneva la famosa statua bicipite del dio; divenne celebre per un rito che la tradizione riferiva ad una legge di Numa (<i>Numa ... Ianum ad infimum Argiletum indicem pacis bellique fecit...</i>, Tito Livio I, 19, 2); tale rito consisteva nell’apertura o nella chiusura del tempio, rispettivamente in caso di guerra o di pace. Il rito suddetto ha dato luogo a due versioni: quella più comune presenta Giano come guardiano della Pace, rinchiusa nel suo santuario (Ovidio F. I, 281: “Pace fores obdo, ne qua discedere possit” e Orazio in Ep. lI, 1, 255, esprime il medesimo concetto); l’altra, in contrapposizione, è quella del poeta Virgilio che immagina la Guerra rinchiusa nel tempio, sotto la sorveglianza del dio. Tutte e due le interpretazioni giustificavano gli epiteti di <i>Patulcius </i>e di <i>Clusius </i>attribuiti alla divinità.<br>',
        ),
        3 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'portaianum2.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, tempio di giano',
          ),
          'body' => '<b class="fs19 cf1"><br></b><b class="fs19 cf1">Il tempio di Giano</b><br>La collocazione esatta del tempio è incerta, sebbene sia comunemente collocato nell’Argileto, vicino alla Basilica Emilia. Le fonti antiche sono di parere discorde a questo proposito. Lo storico Livio infatti lo colloca <i>ad infimum Argiletum</i>, il poeta Ovidio tra il foro repubblicano e quello di Cesare (“hic ubi iunctaforis templa duobus habes”, F. I, 258) e Macrobio ai piedi del Viminale. Le uniche immagini dell’edificio, scomparso senza lasciare alcuna traccia, ci vengono da alcune monete di Nerone, il quale celebrò la chiusura del santuario con una serie emessa dalle zecche di Roma e di Lugdunum. Ci si stupisce che né il dio né il suo tempio appaiano nell’iconografia monetaria del primo imperatore. Augusto, infatti, pur mettendo in risalto nelle <i>Res Gestae</i> la chiusura del tempio di Giano, non ne riporta raffigurazioni sulle monete, né questa può essere sostituita dalla rappresentazione della Pax, riportata in alcune emissioni, Pax troppo spesso ricorrente tra i tipi monetali senza che poi ci fosse una puntuale corrispondenza con tale stato di cose. Questo santuario deve distinguersi dall’altro tempio di Giano, che le fonti collocano <i>iuxta theatrum Marcelli</i> e che fu costruito da C. Duilio durante la prima guerra punica e restaurato da Tiberio nel 17 d.C. Il più antico ed importante santuario di Giano, che fu chiuso in rare occasioni quando l’impero era in pace, era costituito da due archi uniti tra loro da un muro. La statua bicipite della divinità era collocata al centro del passaggio, che con molta probabilità doveva essere un’antica porta della città.',
        ),
        4 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'portaianum.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, sesterzio tempio di giano',
          ),
          'body' => '<b class="fs19 cf1"><br></b><b class="fs19 cf1">La rappresentazione del tempio di Giano sulle monete</b><br>Giano, divinità autoctona, romano sin dalle origini, non riceve alcuna dedica né a Roma né nel Lazio, dove aveva regnato ai bei tempi dell’età dell’oro; non compare neanche nella scultura monumentale ufficiale, né rappresentato da solo, né in compagnia di imperatori o di grandi divinità. Invece Giano e il suo tempio figurano occasionalmente al rovescio delle monete o dei medaglioni coniati a Roma. Il significato politico, religioso, storico e commemorativo di queste rappresentazioni monetarie varia da una emissione all’altra. Varia in funzione delle circostanze, ma anche in funzione stessa della polivalenza di Giano, dio della pace e della guerra, del caos e del cielo, della luce solare e del tempo. Talvolta il dio viene celebrato dall’iconografia monetaria in epoche che non coincidono con momenti di pace universale. Significative sono anche le “assenze”, dove invece ci si aspetterebbe un riferimento, un’allusione. Così la chiusura del tempio di Giano è illustrata dalle emissioni di Nerone, ma non da quelle di Augusto, di Marco Aurelio e di Gordiano III, che invece possiamo affermare avere chiuso in maniera simbolica la Guerra (o la Pace) dietro le pesanti porte di bronzo. Il dio bifronte non trova spazio, come abbiamo visto, nella monetazione di Augusto, ma neanche in quella di Tiberio e di Caligola. Nessuna chiusura del tempio è segnalata dalle fonti sotto questi due regni, neppure sotto Claudio. La presa del potere da parte di Claudio coincideva o almeno poteva coincidere con il terzo centenario del tempio di Giano, innalzato nel foro Olitorio nel 260 a.C. da C. Duilio. Tra le personificazioni che aprono la serie dei denari e aurei di Claudio nel 41-42, c’è la <i>Pax Augusta</i>; i rovesci del tipo PACI AVGVSTAE avrebbero allora ricordato che l’alba di una nuova era di pace corrispondeva al trecentesimo anniversario di questa consacrazione nel foro Olitorio. Ciononostante è la chiusura non di questo tempio, ma di quello di Giano <i>Geminus </i>che segnava la Pace.',
        ),
        5 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'ianum.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, giano bifronte',
          ),
          'body' => 'Alcune monete di Nerone commemorano la chiusura del tempio di Giano dopo la vittoria di Corbulone. Gli aurei rappresentano in maniera semplice, senza infondere alcuna profondità all’immagine, la facciata rettangolare del tempio con la porta a due battenti, seguendo una frontalità piatta e quasi astratta. Al contrario gli assi, i dupondi e i sesterzi presentano il tempio di Giano visto di prospettiva, rappresentato di tre quarti, con la porta ora volta a destra, ora a sinistra. Le ante, provviste di due grossi anelli, sono divise in tre sezioni. Sono le famose porte di bronzo di cui ci parlano Virgilio e Procopio. Spesso una ghirlanda semicircolare segna l’architrave. Sulla facciata laterale, disposte in maniera visibile a sinistra dell’entrata, altre ghirlande segnano il limite superiore o inferiore di un fregio di viticci fioriti. Al di sopra di questo fregio floreale una sorta di attico reca un elegante decoro di palmette, che corona tutto l’edificio. L’unico cenno che possediamo è quello di Procopio, che ci descrive il tempio, che era tutto di bronzo, di forma quadrata, grande quanto basta per coprire la statua bronzea e bifronte del dio. Tutti gli studiosi sono concordi nell’affermare che tale descrizione si accorda molto bene all’immagine fornita dalle monete.<br>',
        ),
        6 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'ianum1.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, sesterzio tempio di giano',
          ),
          'body' => '<b class="fs19 cf1"><br></b><b class="fs19 cf1">Significato della rappresentazione del tempio sulle monete</b><br>Nel discorso programmatico dopo l’avvento al trono, redatto da Seneca, Nerone, pur asserendo di volersi ispirare ai brillanti esempi di governo fornitigli da Augusto, mette l’accento sull’atmosfera di serenità che caratterizza l’inizio del suo regno: niente guerra civile, nessun dissidio interno, niente odio, né rancore. La chiusura del tempio di Giano consacrava il protettorato di Roma sull’Armenia. La leggenda PACE P(opuli) R(omani) TERRA MARIQ(ue) PARTA IANVM CLVSJT fa eco all’espressione delle <i>Res Gestae.</i> Alcuni assi e dupondi, però, portano la leggenda PACE VBIQ(ue) PARTA, che sottolinea la preoccupazione di glorificare la pace imperiale come universale. Questa variante vuole singolarizzare anche una chiusura del tempio, che nel 66 aveva il vantaggio di compiersi 300 anni dopo la sola attestata per l’epoca repubblicana, quella del 235 a.C. Le monete che commemorano l’avvenimento furono coniate a partire dal 64 e molte dal 66. È problematico accordare le fonti relative alla chiusura del tempio, avvenuta nel 66, con le emissioni monetali che cominciano a riprodurre il tempio di Giano dal 64. Lo storico Svetonio colloca la chiusura del tempio di Giano <i>Geminus </i>subito dopo l’incoronazione di Tiridate a Roma, avvenuta con molta probabilità nel 66: “ob quae imperator consalutatus, laurea in Capitolium lata, lanum Gemi num clausit, tam nullo quam residuo bello”. Svetonio quindi afferma che la chiusura avvenne nel 66 d.C., mentre le prime serie monetali sono del 64 d.C.',
        ),
        7 => 
        array (
          'type' => 'split',
          'image' => 
          array (
            'file' => 'portaian.jpg',
            'alt' => 'moneta romana imperiale, monete romane imperiali, tempio di giano',
          ),
          'body' => 'Il Mattingly crede che la cerimonia sia stata ripetuta formalmente nel 66, dopo essere stata originariamente celebrata nel 64. Secondo l’autore, infatti, Nerone aveva urgente bisogno di rassicurare con qualsiasi mezzo, l’opinione pubblica, preoccupata dopo l’incendio di Roma. Secondo il Grant i conii del 64 preannuncerebbero la chiusura del tempio, posposta nel 66 da Nerone per farla coincidere con il terzo centenario, che cadeva proprio in quell’anno, della prima chiusura, ricordata da T. Manlio nel 253 a.C. E’ probabile che si diffondesse l’immagine del tempio di Giano con le porte chiuse, accompagnato dalla leggenda IANVM CLVSIT, affinché l’opinione pubblica che attendeva la pace ne fosse positivamente influenzata. La propaganda imperiale che veniva attuata anche mediante i tipi monetali pubblicizza e spesso anticipa gli avvenimenti. Possiamo quindi ipotizzare che questo sia il nostro caso: Nerone rivalorizzò e ripopolarizzò il culto di Giano in favore della Pace, ma attese il 66 per solennizzarla con una commemorazione ufficiale. La chiusura effettiva poteva essere avvenuta nel 64 o nel 66, ma se ne procrastinò intenzionalmente la cerimonia affinché questa seguisse e concludesse la visita di Tiridate, e quindi rappresentasse un omaggio e un riconoscimento di sottomissione al monarca universale.<br><i style="line-height: 20px;" class="cf1 ff1"><i class="fs14">Francesca Barenghi</i></i>',
        ),
