          'paragraphs' => 
          array (
            0 => '<b class="fs14">Il Pegaso</b><br>Il "Pegaso" era la moneta in argento del peso di circa 8,5 grammi equivalente ad una didramma euboico-attica, ma del valore di 3 dracme, coniata nella zecca di Corinto a partire dalla metà del VI a.C. Al dritto reca la figura di un cavallo alato, con le punte delle ali generalmente ricurve, fissato nel metallo nell\'atto di spiccare il volo verso destra o sinistra, mentre al rovescio la testa della dea Atena vestita dell\'elmo corinzio prende il posto dell\'iniziale quadrato incuso, variamente partito, presente sulle serie più arcaiche. Il pegaso e la dea Atena raffigurati sulle due facce della medesima moneta rappresentavano lo stretto legame che collegava tra loro i due principali culti venerati nella città di Corinto. Al di fuori della Grecia propria, il "Pegaso" si diffuse esclusivamente in Occidente particolarmente in Sicilia dove, tra la seconda metà del IV e gli inizi del III secolo a.C., si affermò come il circolante comunemente usato negli scambi commerciali.',
          ),
        ),
      ),
    ),
    'tetradrachm_alexander' => 
    array (
      'title' => 'Il tetradramma di Alessandro Magno',
      'lead' => 'La monetazione di Alessandro Magno.',
      'blocks' => 
