    'byzantine_solidus' => 
    array (
      'title' => 'Il solido bizantino',
      'lead' => 'Il solido nell\'Impero bizantino.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => '3a.jpg',
            'alt' => 'solido bizantino, solidi bizantini ',
